INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2501-10-5KEY', 'Продолжите фразу', 'Открытые вопросы о карьере и ценностях', 'core', 1, '{"type":"open_questions","instruction":"Продолжите фразу:","questions":[{"id":1,"text":"Карьера мечты — это когда..."},{"id":2,"text":"Мой жизненный девиз — это..."},{"id":3,"text":"Я по-настоящему счастлив в работе, когда..."},{"id":4,"text":"Идеальный руководитель для меня..."},{"id":5,"text":"Идеальный коллектив для меня..."}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2520-10-ETYA', 'Мои качества', 'Выберите 12 прилагательных «Мои качества»', 'core', 2, '{"type":"multi_select","instruction":"Выберите 12 прилагательных «Мои качества»","answerKey":"chosen_qualities","minSelections":12,"maxSelections":12,"options":[{"id":1,"label":"Оптимистичный"},{"id":2,"label":"Дисциплинированный"},{"id":3,"label":"Независимый"},{"id":4,"label":"Стабильный"},{"id":5,"label":"Харизматичный"},{"id":6,"label":"Решительный"},{"id":7,"label":"Заботливый"},{"id":8,"label":"Детальный"},{"id":9,"label":"Напористый"},{"id":10,"label":"Коммуникабельный"},{"id":11,"label":"Надежный"},{"id":12,"label":"Организованный"},{"id":13,"label":"Целеустремленный"},{"id":14,"label":"Вдохновляющий"},{"id":15,"label":"Аналитический"},{"id":16,"label":"Спокойный"},{"id":17,"label":"Конкурентный"},{"id":18,"label":"Влиятельный"},{"id":19,"label":"Стрессоустойчивый"},{"id":20,"label":"Логичный"},{"id":21,"label":"Настойчивый"},{"id":22,"label":"Энергичный"},{"id":23,"label":"Уравновешенный"},{"id":24,"label":"Последовательный"},{"id":25,"label":"Смелый"},{"id":26,"label":"Общительный"},{"id":27,"label":"Рассудительный"},{"id":28,"label":"Лояльный"},{"id":29,"label":"Волевой"},{"id":30,"label":"Энтузиаст"},{"id":31,"label":"Дипломатичный"},{"id":32,"label":"Аккуратный"},{"id":33,"label":"Предприимчивый"},{"id":34,"label":"Убедительный"},{"id":35,"label":"Поддерживающий"},{"id":36,"label":"Систематичный"},{"id":37,"label":"Доминантный"},{"id":38,"label":"Открытый"},{"id":39,"label":"Точный"},{"id":40,"label":"Терпеливый"},{"id":41,"label":"Авторитетный"},{"id":42,"label":"Красноречивый"},{"id":43,"label":"Гармоничный"},{"id":44,"label":"Скрупулезный"},{"id":45,"label":"Твердый"},{"id":46,"label":"Дружелюбный"},{"id":47,"label":"Наблюдательный"},{"id":48,"label":"Отзывчивый"}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2521-10-NEYA', 'Точно НЕ про меня', 'Выберите 8 прилагательных «Точно НЕ про меня»', 'core', 3, '{"type":"multi_select","instruction":"Выберите 8 прилагательных «Точно НЕ про меня»","answerKey":"rejected_qualities","minSelections":8,"maxSelections":8,"options":[{"id":1,"label":"Напористый"},{"id":2,"label":"Терпеливый"},{"id":3,"label":"Детальный"},{"id":4,"label":"Харизматичный"},{"id":5,"label":"Независимый"},{"id":6,"label":"Дисциплинированный"},{"id":7,"label":"Влиятельный"},{"id":8,"label":"Стабильный"},{"id":9,"label":"Точный"},{"id":10,"label":"Решительный"},{"id":11,"label":"Общительный"},{"id":12,"label":"Надежный"},{"id":13,"label":"Последовательный"},{"id":14,"label":"Целеустремленный"},{"id":15,"label":"Красноречивый"},{"id":16,"label":"Спокойный"},{"id":17,"label":"Рассудительный"},{"id":18,"label":"Настойчивый"},{"id":19,"label":"Дружелюбный"},{"id":20,"label":"Уравновешенный"},{"id":21,"label":"Скрупулезный"},{"id":22,"label":"Смелый"},{"id":23,"label":"Оптимистичный"},{"id":24,"label":"Лояльный"},{"id":25,"label":"Аккуратный"},{"id":26,"label":"Волевой"},{"id":27,"label":"Энтузиаст"},{"id":28,"label":"Гармоничный"},{"id":29,"label":"Систематичный"},{"id":30,"label":"Предприимчивый"},{"id":31,"label":"Коммуникабельный"},{"id":32,"label":"Поддерживающий"},{"id":33,"label":"Аналитический"},{"id":34,"label":"Доминантный"},{"id":35,"label":"Открытый"},{"id":36,"label":"Организованный"},{"id":37,"label":"Заботливый"},{"id":38,"label":"Авторитетный"},{"id":39,"label":"Убедительный"},{"id":40,"label":"Отзывчивый"},{"id":41,"label":"Логичный"},{"id":42,"label":"Конкурентный"},{"id":43,"label":"Энергичный"},{"id":44,"label":"Стрессоустойчивый"},{"id":45,"label":"Наблюдательный"},{"id":46,"label":"Твердый"},{"id":47,"label":"Вдохновляющий"},{"id":48,"label":"Дипломатичный"}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2530-10-12F4', 'Распределение 10 баллов (DISC)', 'Распределите 10 баллов по вариантам', 'core', 4, '{"type":"allocate_points","instruction":"Распределите 10 баллов, не более 5 на каждый пункт","totalPoints":10,"maxPerOption":5,"questions":[{"id":1,"text":"Как вы обычно принимаете решения:","options":[{"id":1,"label":"Подробно анализируя все факты и детали"},{"id":2,"label":"Быстро и решительно, полагаясь на интуицию"},{"id":3,"label":"Взвешивая все \"за\" и \"против\", учитывая мнения других"},{"id":4,"label":"Медленно и осторожно, избегая рисков"}]},{"id":2,"text":"Что вас больше всего мотивирует в работе:","options":[{"id":1,"label":"Работа в команде и общение с людьми"},{"id":2,"label":"Стабильность и предсказуемость рабочего процесса"},{"id":3,"label":"Точность и качество выполняемых задач"},{"id":4,"label":"Возможность добиться результатов и превзойти конкурентов"}]},{"id":3,"text":"Как вы реагируете на конфликтные ситуации:","options":[{"id":1,"label":"Избегаю конфронтации, предпочитаю сохранить мир"},{"id":2,"label":"Анализирую ситуацию и предлагаю логическое решение"},{"id":3,"label":"Прямо высказываю свою позицию и отстаиваю ее"},{"id":4,"label":"Стараюсь найти компромисс, учитывающий интересы всех сторон"}]},{"id":4,"text":"Какой темп работы вам больше подходит:","options":[{"id":1,"label":"Методичный темп с возможностью глубокого анализа"},{"id":2,"label":"Высокий темп с частой сменой задач"},{"id":3,"label":"Размеренный, стабильный темп работы"},{"id":4,"label":"Активный темп с возможностью общения"}]},{"id":5,"text":"Как вы предпочитаете получать обратную связь:","options":[{"id":1,"label":"Деликатно и конфиденциально"},{"id":2,"label":"Прямо и без лишних деталей"},{"id":3,"label":"С конкретными фактами и примерами"},{"id":4,"label":"В дружественной, поддерживающей форме"}]},{"id":6,"text":"Что для вас важнее всего в команде:","options":[{"id":1,"label":"Хорошие отношения между участниками"},{"id":2,"label":"Компетентность и профессионализм коллег"},{"id":3,"label":"Стабильность состава и четкие роли"},{"id":4,"label":"Достижение поставленных целей"}]},{"id":7,"text":"Как вы относитесь к изменениям:","options":[{"id":1,"label":"Принимаю изменения только после подробного анализа"},{"id":2,"label":"Принимаю изменения, если они не нарушают командный дух"},{"id":3,"label":"Приветствую изменения, если они ведут к улучшению результатов"},{"id":4,"label":"Предпочитаю стабильность, изменения вызывают беспокойство"}]},{"id":8,"text":"Какой стиль общения вам ближе:","options":[{"id":1,"label":"Спокойный, ровный, терпеливый"},{"id":2,"label":"Точный, детальный, основанный на фактах"},{"id":3,"label":"Открытый, дружелюбный, эмоциональный"},{"id":4,"label":"Прямой, краткий, по делу"}]},{"id":9,"text":"Как вы ведете себя под давлением:","options":[{"id":1,"label":"Обращаюсь за поддержкой к другим людям"},{"id":2,"label":"Становлюсь более решительным и активным"},{"id":3,"label":"Сосредотачиваюсь на анализе ситуации"},{"id":4,"label":"Становлюсь более осторожным и медлительным"}]},{"id":10,"text":"Что вас больше всего раздражает в работе других:","options":[{"id":1,"label":"Поспешность и давление"},{"id":2,"label":"Холодность и отсутствие эмоций"},{"id":3,"label":"Медлительность и нерешительность"},{"id":4,"label":"Неточность и поверхностность"}]},{"id":11,"text":"Как вы предпочитаете планировать свое время:","options":[{"id":1,"label":"Методично, выделяя достаточно времени на каждую задачу"},{"id":2,"label":"С учетом времени на общение и взаимодействие с людьми"},{"id":3,"label":"Гибко, с возможностью быстро переключаться между задачами"},{"id":4,"label":"Детально, с четким распорядком и буферным временем"}]},{"id":12,"text":"Что для вас означает успех:","options":[{"id":1,"label":"Стабильность и безопасность в работе и жизни"},{"id":2,"label":"Достижение поставленных целей и победа над конкурентами"},{"id":3,"label":"Признание окружающих и хорошие отношения в коллективе"},{"id":4,"label":"Высокое качество работы и профессиональная компетентность"}]}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2540-10-64QN', 'Личностный опросник (64 вопроса)', 'Шкала 0–4', '64qn', 1, '{"type":"scale_0_4","instruction":"0 — совершенно неверно, 4 — совершенно верно","questions":[{"id":1,"text":"Я умею настоять на своем"},{"id":2,"text":"Мне нужна поддержка других людей"},{"id":3,"text":"Я всегда готов прийти на помощь"},{"id":4,"text":"Я могу быть резким в общении"},{"id":5,"text":"Мне трудно возражать другим людям"},{"id":6,"text":"Я всегда думаю прежде всего о своих интересах"},{"id":7,"text":"Я стараюсь помочь людям в трудной ситуации"},{"id":8,"text":"Я с осторожностью отношусь к новым знакомствам"},{"id":9,"text":"Люди часто обращаются ко мне за советом"},{"id":10,"text":"Я часто соглашаюсь против своего желания"},{"id":11,"text":"Я часто обращаюсь за помощью к окружающим"},{"id":12,"text":"Мне нравится работать в команде"},{"id":13,"text":"Когда злюсь, то не сдерживаю эмоций"},{"id":14,"text":"Мне важно заботиться о других людях"},{"id":15,"text":"Мне трудно просить о помощи других людей"},{"id":16,"text":"Мне трудно доверять людям"},{"id":17,"text":"Мне нравится быть главным в группе"},{"id":18,"text":"В компании я предпочитаю молчать"},{"id":19,"text":"Мне трудно принимать решения самостоятельно"},{"id":20,"text":"Я легко иду на компромисс ради общего дела"},{"id":21,"text":"Я открыто выражаю свое недовольство"},{"id":22,"text":"Я часто жертвую своими интересами ради близких"},{"id":23,"text":"Я предпочитаю полагаться только на себя"},{"id":24,"text":"Я часто сомневаюсь в искренности других"},{"id":25,"text":"Я легко принимаю ответственные решения"},{"id":26,"text":"Мне сложно отстаивать свое мнение"},{"id":27,"text":"Я предпочитаю, чтобы другие брали инициативу"},{"id":28,"text":"В отношениях я проявляю терпимость"},{"id":29,"text":"Мне трудно промолчать, когда что-то не нравится"},{"id":30,"text":"Мне нравится опекать других"},{"id":31,"text":"В конфликте я защищаю свои права любой ценой"},{"id":32,"text":"В людях я в первую очередь замечаю недостатки"},{"id":33,"text":"В споре я обычно отстаиваю свою точку зрения"},{"id":34,"text":"Я избегаю конфликтных ситуаций"},{"id":35,"text":"Мне важно одобрение со стороны других"},{"id":36,"text":"Я стремлюсь к сотрудничеству с окружающими"},{"id":37,"text":"Я могу грубо ответить, если меня раздражают"},{"id":38,"text":"Я беру на себя ответственность за других людей"},{"id":39,"text":"Я редко иду на компромиссы"},{"id":40,"text":"Я предпочитаю держать дистанцию в отношениях"},{"id":41,"text":"Я способен организовать работу других людей"},{"id":42,"text":"Мне легче подчиниться, чем спорить"},{"id":43,"text":"Я нуждаюсь в постоянной поддержке"},{"id":44,"text":"Мне важно поддерживать хорошие отношения"},{"id":45,"text":"В конфликте я готов идти до конца"},{"id":46,"text":"Мне приятно делать добрые дела"},{"id":47,"text":"Мне важнее собственное мнение, чем мнение окружающих"},{"id":48,"text":"Мне кажется, что люди часто обманывают"},{"id":49,"text":"Мне важно, чтобы меня уважали и слушались"},{"id":50,"text":"Я стесняюсь высказывать свои идеи"},{"id":51,"text":"Без помощи других мне трудно справляться с задачами"},{"id":52,"text":"Я готов поступиться своими интересами ради других"},{"id":53,"text":"Я не скрываю своих негативных эмоций"},{"id":54,"text":"Я стараюсь защитить слабых"},{"id":55,"text":"Я не люблю зависеть от других людей"},{"id":56,"text":"Я критически оцениваю поступки окружающих"},{"id":57,"text":"Я предпочитаю командовать, а не подчиняться"},{"id":58,"text":"В группе я чаще следую за другими"},{"id":59,"text":"Я часто ищу совета у знакомых"},{"id":60,"text":"В конфликте я ищу решение, устраивающее всех"},{"id":61,"text":"Мне легче высказать претензию прямо в лицо"},{"id":62,"text":"В отношениях я проявляю великодушие"},{"id":63,"text":"В трудной ситуации рассчитываю только на свои силы"},{"id":64,"text":"В группе я чувствую себя обособленно"}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2550-10-1IN2', 'Дилеммы: Выбор из двух', 'Выберите один вариант', 'core', 5, '{"type":"binary_choice","instruction":"Выберите один из вариантов","questions":[{"id":1,"option1":"Стабильность компании","option2":"Амбициозные цели"},{"id":2,"option1":"Дружный коллектив","option2":"Свобода принятия решений"},{"id":3,"option1":"Экспертная команда","option2":"Гибкие процессы"},{"id":4,"option1":"Карьерный рост","option2":"Социальная значимость проекта"},{"id":5,"option1":"Система наставничества","option2":"Возможность реализовать идеи"},{"id":6,"option1":"Комфортный офис","option2":"Гибкий график"},{"id":7,"option1":"Предсказуемость работы","option2":"Инновационные проекты"},{"id":8,"option1":"Опытный лидер","option2":"Командная автономия"},{"id":9,"option1":"Социальные бонусы и льготы","option2":"Профессиональные вызовы"},{"id":10,"option1":"Польза для общества","option2":"Личное признание"}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2551-10-GNFL', 'Положительные факторы работодателя', 'Выберите 3 фактора', 'core', 6, '{"type":"multi_select","instruction":"Выберите 3 положительных фактора","answerKey":"positive_factors","minSelections":3,"maxSelections":3,"options":[{"id":1,"label":"Социальные льготы и бонусы"},{"id":2,"label":"Стабильность компании"},{"id":3,"label":"Комфортный офис"},{"id":4,"label":"Дружный коллектив"},{"id":5,"label":"Гибкий график"},{"id":6,"label":"Социальная значимость"},{"id":7,"label":"Экспертная команда"},{"id":8,"label":"Возможность реализовать свои идеи"},{"id":9,"label":"Гибкие процессы"},{"id":10,"label":"Свобода принятия решений"},{"id":11,"label":"Карьерный рост"},{"id":12,"label":"Система наставничества"},{"id":13,"label":"Предсказуемость работы"},{"id":14,"label":"Польза для общества"},{"id":15,"label":"Амбициозные цели"},{"id":16,"label":"Опытный лидер команды"}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2552-10-RDFL', 'Раздражающие факторы в работе', 'Выберите 6 факторов', 'core', 7, '{"type":"multi_select","instruction":"Выберите 6 раздражающих факторов","answerKey":"annoying_factors","minSelections":6,"maxSelections":6,"options":[{"id":1,"label":"Отсутствие контроля в управлении"},{"id":2,"label":"Нет доверия к сотрудникам"},{"id":3,"label":"Отсутствие обратной связи"},{"id":4,"label":"Однообразие задач"},{"id":5,"label":"Игнорирование инноваций"},{"id":6,"label":"Непрозрачная система роста"},{"id":7,"label":"Игнорирование идей и заслуг"},{"id":8,"label":"Нарушение личных границ"},{"id":9,"label":"Система штрафов"},{"id":10,"label":"Игнорирование достижений"},{"id":11,"label":"Отсутствие соц. пакета"},{"id":12,"label":"Авторитарное управление"},{"id":13,"label":"Микроменеджмент"},{"id":14,"label":"Жесткий график"},{"id":15,"label":"Медлительность команды"},{"id":16,"label":"Жесткое давление"},{"id":17,"label":"Ответственность за всех"},{"id":18,"label":"Подавление инициативы"},{"id":19,"label":"Культ переработок"},{"id":20,"label":"Невыполнение обязательств"},{"id":21,"label":"Вред обществу"},{"id":22,"label":"Высокая требовательность руководства"},{"id":23,"label":"Токсичность коллег"},{"id":24,"label":"Отсутствие мозговых штурмов"},{"id":25,"label":"Частые обсуждения и совещания"},{"id":26,"label":"Присвоение заслуг"},{"id":27,"label":"Резкие изменения целей"},{"id":28,"label":"Размытые задачи"},{"id":29,"label":"Монотонность работы"},{"id":30,"label":"Консервативные методы"},{"id":31,"label":"Беспорядок процессов"},{"id":32,"label":"Высокая бюрократия"}]}'::jsonb, NOW(), NOW());
INSERT INTO surveys (code, name, description, group_code, sort_order, questions, created_at, updated_at) VALUES ('2560-10-BLBN', 'Тест Белбина — командные роли', '10 баллов на утверждение', 'core', 8, '{"type":"belbin_matrix","instruction":"Распределите 10 баллов","totalPoints":10,"maxPerOption":5,"questions":[{"id":1,"text":"Чем я могу помочь команде:","options":[{"id":1,"label":"Я думаю, что могу быстро выявлять и использовать новые возможности."},{"id":2,"label":"Я могу успешно работать с разными типами людей."},{"id":3,"label":"Разработка идей является моим естественным достоинством"},{"id":4,"label":"Я обладаю способностью находить в других людях такие качества, которые могут быть полезны для всей группы."},{"id":5,"label":"Моя способность доводить дело до завершения во многом определяет мою личную эффективность."},{"id":6,"label":"Я готов смириться с временной непопулярностью, если это положительно повлияет на результаты работы команды."},{"id":7,"label":"Я быстро понимаю, что надо делать в хорошо знакомой мне ситуации."},{"id":8,"label":"Я могу предложить набор разумных вариантов действий без предубеждений и пристрастий."}]},{"id":2,"text":"Если с точки зрения командной работы у меня есть недостатки, то они таковы:","options":[{"id":1,"label":"Я не успокоюсь до тех пор, пока не пойму, что рабочие встречи команды хорошо организованы, подготовлены и проводятся правильно."},{"id":2,"label":"Я благосклонен к людям, выдвигающим оригинальные предложения."},{"id":3,"label":"Я страдаю многословием, когда группа обсуждает новые идеи."},{"id":4,"label":"Моя страсть возражать по любому поводу мешает мне присоединиться к моим коллегам."},{"id":5,"label":"Я иногда кажусь человеком авторитарным, стремящимся повлиять на других людей."},{"id":6,"label":"Мне трудно проявить инициативу, потому что я поддаюсь настроению, установившемуся в группе."},{"id":7,"label":"Я углубляюсь в свои размышления до такой степени, что теряю контроль над тем, что происходит."},{"id":8,"label":"Мои коллеги считают, что я слишком волнуюсь из-за мелочей и опасений, что дела могут пойти не так, как надо."}]},{"id":3,"text":"Когда я работаю над проектом вместе с другими людьми:","options":[{"id":1,"label":"Я могу влиять на коллег без давления на них."},{"id":2,"label":"Моя врожденная осмотрительность позволяет мне предотвращать небрежности, ошибки и упущения."},{"id":3,"label":"Я готов потребовать от коллег четкости, чтобы время не уходило впустую и участники совещания не отклонялись от главной темы."},{"id":4,"label":"Меня можно признать человеком, способным придумать что-нибудь оригинальное."},{"id":5,"label":"Я всегда готов поддержать предложение, полезное для команды."},{"id":6,"label":"Я интересуюсь новейшими идеями и разработками."},{"id":7,"label":"Я думаю, что моя способность к холодному расчету находит поддержку у других людей."},{"id":8,"label":"На меня можно положиться при организации важной работы."}]},{"id":4,"text":"Мое отношение к командной работе проявляется в следующем:","options":[{"id":1,"label":"Я стремлюсь хорошо знать своих коллег."},{"id":2,"label":"Я неохотно обмениваюсь мнениями с другими людьми и свое особое мнение держу при себе."},{"id":3,"label":"Я нахожу убедительные аргументы при необходимости отвергнуть пустые аргументы."},{"id":4,"label":"Я думаю, что у меня есть талант организатора планомерной работы."},{"id":5,"label":"Я склонен отвергать очевидное и предлагать неожиданное."},{"id":6,"label":"Я проявляю высокую требовательность к себе при выполнении командной роли, которую на меня возлагают."},{"id":7,"label":"Я готов самостоятельно осуществлять контакты за пределами группы."},{"id":8,"label":"Я интересуюсь различными точками зрения, но принятое решение выполняю без колебаний."}]},{"id":5,"text":"Я получаю удовлетворение от работы, потому что:","options":[{"id":1,"label":"Мне нравится анализировать сложные ситуации и взвешивать всевозможные варианты."},{"id":2,"label":"Мне интересно находить решения различных проблем."},{"id":3,"label":"Мне нравится осознавать, что я стимулирую хорошие рабочие взаимоотношения."},{"id":4,"label":"Я оказываю существенное влияние на процесс принятия решений."},{"id":5,"label":"Я умею находить людей, которые могут предложить что-нибудь новое."},{"id":6,"label":"Я способен убедить людей в необходимости тех или иных действий."},{"id":7,"label":"Я чувствую, когда мне необходимо полностью сосредоточиться на поставленной задаче."},{"id":8,"label":"Я люблю деятельность, которая развивает мое воображение."}]},{"id":6,"text":"Если мне вместе с группой незнакомых людей неожиданно поручат трудную задачу, которую надо выполнить быстро:","options":[{"id":1,"label":"Я предпочел бы уединиться и хорошо обдумать ситуацию, прежде чем разработать план действий."},{"id":2,"label":"Я готов работать с человеком, который проявил позитивный подход к делу, каким бы трудным этот человек ни казался."},{"id":3,"label":"Я попытался бы разделить общую задачу на ряд мелких и установил бы, какой вклад в решение задачи могут внести конкретные члены команды."},{"id":4,"label":"Моя врожденная обязательность помогает мне контролировать сроки выполнения задания."},{"id":5,"label":"Я способен сохранять невозмутимость и думать по существу."},{"id":6,"label":"Я могу следовать к намеченной цели, несмотря ни на какое давление."},{"id":7,"label":"Я готов взять на себя роль ведущего, если чувствую, что группа не продвигается в решении задачи."},{"id":8,"label":"Я начну дискуссию, чтобы стимулировать коллег на новые мысли и привести группу в движение."}]},{"id":7,"text":"Проблемы, которые я должен преодолеть, работая в группе:","options":[{"id":1,"label":"Я склонен к раздражительности по отношению к тем, кто мешает группе продвигаться к цели."},{"id":2,"label":"Я могу вызвать критику со стороны коллег из-за моего увлечения анализом проблем и недостаточно развитой интуиции."},{"id":3,"label":"Мое стремление задать правильный ход работе может привести к задержке выполнения задачи."},{"id":4,"label":"Я быстро теряю интерес к делу и надеюсь на кого-нибудь из команды, кто заменит меня."},{"id":5,"label":"Мне трудно начать работу, пока я полностью не пойму цели этой работы."},{"id":6,"label":"Мне не всегда удается объяснить сложные идеи, которые рождает мой разум."},{"id":7,"label":"Я сознаю необходимость поручать другим сделать то, что сам сделать не мог."},{"id":8,"label":"Я становлюсь нерешительным, когда сталкиваюсь с сильным сопротивлением."}]}]}'::jsonb, NOW(), NOW());
INSERT INTO survey_keys (survey_id, scoring_logic, keys_data, created_at, updated_at)
